@namespace sv_7c3625fc74cc414b97ba7a94df488db7.Components.Pages.Apply

<div class="step-content">
    <h4>Review & Submit</h4>

    @if (IsSubmitted)
    {
        <div class="alert alert-success">
            <h5>Application Submitted Successfully!</h5>
            <p>Your application ID is: <strong>@ApplicationId</strong></p>
            <p>Thank you for applying. We will review your application and get back to you.</p>
        </div>
    }
    else
    {
        @if (!string.IsNullOrEmpty(ErrorMessage))
        {
            <div class="alert alert-danger">@ErrorMessage</div>
        }

        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>Personal Information</strong>
                <a href="#" @onclick="() => OnEditStep.InvokeAsync(0)" @onclick:preventDefault>Edit</a>
            </div>
            <div class="card-body">
                <p><strong>Name:</strong> @Personal?.FullName</p>
                <p><strong>Email:</strong> @Personal?.Email</p>
                <p><strong>Phone:</strong> @Personal?.Phone</p>
                <p><strong>Address:</strong> @Personal?.Address</p>
            </div>
        </div>

        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>Work History</strong>
                <a href="#" @onclick="() => OnEditStep.InvokeAsync(1)" @onclick:preventDefault>Edit</a>
            </div>
            <div class="card-body">
                @if (Work?.Entries is not null)
                {
                    @foreach (var entry in Work.Entries)
                    {
                        <div class="mb-2">
                            <strong>@entry.Title</strong> at @entry.Company<br />
                            <small class="text-muted">
                                @entry.StartDate.ToString("MMM yyyy") &mdash;
                                @(entry.EndDate?.ToString("MMM yyyy") ?? "Present")
                            </small>
                            @if (!string.IsNullOrWhiteSpace(entry.Description))
                            {
                                <p class="mt-1 mb-0">@entry.Description</p>
                            }
                        </div>
                    }
                }
            </div>
        </div>

        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>References</strong>
                <a href="#" @onclick="() => OnEditStep.InvokeAsync(2)" @onclick:preventDefault>Edit</a>
            </div>
            <div class="card-body">
                @if (References is not null)
                {
                    @foreach (var r in References)
                    {
                        <p class="mb-1">
                            <strong>@r.Name</strong> (@r.Relationship) &mdash; @r.Email
                            @if (!string.IsNullOrWhiteSpace(r.Phone))
                            {
                                <span>, @r.Phone</span>
                            }
                        </p>
                    }
                }
            </div>
        </div>

        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>Cover Letter</strong>
                <a href="#" @onclick="() => OnEditStep.InvokeAsync(3)" @onclick:preventDefault>Edit</a>
            </div>
            <div class="card-body">
                <p style="white-space: pre-wrap;">@CoverLetter</p>
            </div>
        </div>

        <div class="d-flex justify-content-between">
            <button type="button" class="btn btn-secondary" @onclick="OnBack">Back</button>
            <button type="button" class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
                @if (IsSubmitting)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                    <span>Submitting...</span>
                }
                else
                {
                    <span>Submit Application</span>
                }
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public PersonalInfo? Personal { get; set; }
    [Parameter] public WorkHistory? Work { get; set; }
    [Parameter] public List<Reference>? References { get; set; }
    [Parameter] public string? CoverLetter { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback<int> OnEditStep { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }

    public bool IsSubmitted { get; set; }
    public int? ApplicationId { get; set; }
    public bool IsSubmitting { get; set; }
    private string? ErrorMessage { get; set; }

    public void ShowConfirmation(int appId)
    {
        ApplicationId = appId;
        IsSubmitted = true;
        IsSubmitting = false;
        StateHasChanged();
    }

    public void ShowError(string message)
    {
        ErrorMessage = message;
        IsSubmitting = false;
        StateHasChanged();
    }

    private async Task HandleSubmit()
    {
        IsSubmitting = true;
        ErrorMessage = null;
        await OnSubmit.InvokeAsync();
    }
}

