arguments.file_text:
@page "/apply"
@namespace sv_7c3625fc74cc414b97ba7a94df488db7.Components.Pages.Apply
@using sv_7c3625fc74cc414b97ba7a94df488db7.Models
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="apply-container">
    <h2 class="mb-4 text-center">Job Application</h2>

    <StepIndicator CurrentStep="@_currentStep" OnStepSelected="GoToStep" />

    <div class="mt-4">
        @switch (_currentStep)
        {
            case 0:
                <PersonalInfoStep Info="@_personalInfo"
                                  ApplicationService="ApplicationService"
                                  OnNext="HandlePersonalInfoNext" />
                break;
            case 1:
                <WorkHistoryStep History="@_workHistory"
                                 OnNext="HandleWorkHistoryNext"
                                 OnBack="GoBack" />
                break;
            case 2:
                <ReferencesStep ExistingReferences="@_references"
                                OnNext="HandleReferencesNext"
                                OnBack="GoBack" />
                break;
            case 3:
                <CoverLetterStep ExistingCoverLetter="@_coverLetter"
                                 OnNext="HandleCoverLetterNext"
                                 OnBack="GoBack" />
                break;
            case 4:
                <ReviewStep @ref="_reviewStep"
                            Personal="@_personalInfo"
                            Work="@_workHistory"
                            References="@_references"
                            CoverLetter="@_coverLetter"
                            OnBack="GoBack"
                            OnEditStep="GoToStep"
                            OnSubmit="HandleSubmit" />
                break;
        }
    </div>
</div>

@code {
    private int _currentStep;
    private PersonalInfo? _personalInfo;
    private WorkHistory? _workHistory;
    private List<Reference>? _references;
    private string? _coverLetter;
    private ReviewStep? _reviewStep;

    private void GoToStep(int step)
    {
        _currentStep = step;
    }

    private void GoBack()
    {
        if (_currentStep > 0)
            _currentStep--;
    }

    private void HandlePersonalInfoNext(PersonalInfo info)
    {
        _personalInfo = info;
        _currentStep = 1;
    }

    private void HandleWorkHistoryNext(WorkHistory history)
    {
        _workHistory = history;
        _currentStep = 2;
    }

    private void HandleReferencesNext(List<Reference> references)
    {
        _references = references;
        _currentStep = 3;
    }

    private void HandleCoverLetterNext(string coverLetter)
    {
        _coverLetter = coverLetter;
        _currentStep = 4;
    }

    private async Task HandleSubmit()
    {
        try
        {
            var application = new JobApplication(
                _personalInfo!,
                _workHistory!,
                _references!,
                _coverLetter!
            );

            var appId = await ApplicationService.SubmitApplicationAsync(application);
            _reviewStep?.ShowConfirmation(appId);
        }
        catch (Exception ex)
        {
            _reviewStep?.ShowError($"Submission failed: {ex.Message}");
        }
    }
}

.apply-container {
    max-width: 800px;
    margin: 2rem auto;
    padding: 0 1rem;
}

/* Step Indicator */
.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 1rem;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    cursor: default;
    min-width: 80px;
}

.step.completed {
    cursor: pointer;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: bold;
    font-size: 0.9rem;
    border: 2px solid #dee2e6;
    background: #fff;
