@namespace sv_7c3625fc74cc414b97ba7a94df488db7.Components.Pages.Apply

<div class="work-entry-form">
    <div class="entry-header">
        <h5>Position @(Index + 1)</h5>
        @if (CanRemove)
        {
            <button type="button" class="btn btn-sm btn-outline-danger" @onclick="OnRemove">Remove</button>
        }
    </div>

    <div class="row mb-2">
        <div class="col-md-6">
            <label class="form-label">Company Name *</label>
            <input type="text" class="form-control" value="@Entry.Company"
                   @onchange="e => Update(Entry with { Company = e.Value?.ToString() ?? "" })" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Job Title *</label>
            <input type="text" class="form-control" value="@Entry.Title"
                   @onchange="e => Update(Entry with { Title = e.Value?.ToString() ?? "" })" />
        </div>
    </div>

    <div class="row mb-2">
        <div class="col-md-4">
            <label class="form-label">Start Date *</label>
            <input type="date" class="form-control" value="@Entry.StartDate.ToString("yyyy-MM-dd")"
                   @onchange="e => Update(Entry with { StartDate = DateTime.Parse(e.Value?.ToString() ?? DateTime.Today.ToString("yyyy-MM-dd")) })" />
        </div>
        <div class="col-md-4">
            <label class="form-label">End Date</label>
            <input type="date" class="form-control" value="@(Entry.EndDate?.ToString("yyyy-MM-dd") ?? "")"
                   disabled="@IsCurrent"
                   @onchange="e => Update(Entry with { EndDate = string.IsNullOrEmpty(e.Value?.ToString()) ? null : DateTime.Parse(e.Value.ToString()!) })" />
        </div>
        <div class="col-md-4 d-flex align-items-end mb-1">
            <div class="form-check">
                <input type="checkbox" class="form-check-input" id="current-@Index" checked="@IsCurrent"
                       @onchange="e => ToggleCurrent((bool)(e.Value ?? false))" />
                <label class="form-check-label" for="current-@Index">Currently working here</label>
            </div>
        </div>
    </div>

    <div class="mb-2">
        <label class="form-label">Description</label>
        <textarea class="form-control" rows="3" value="@Entry.Description"
                  @onchange="e => Update(Entry with { Description = e.Value?.ToString() ?? "" })"></textarea>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntry Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback<WorkEntry> OnEntryChanged { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private bool IsCurrent => Entry.EndDate == null;

    private async Task Update(WorkEntry updated)
    {
        await OnEntryChanged.InvokeAsync(updated);
    }

    private async Task ToggleCurrent(bool isCurrent)
    {
        var updated = isCurrent
            ? Entry with { EndDate = null }
            : Entry with { EndDate = DateTime.Today };
        await OnEntryChanged.InvokeAsync(updated);
    }
}

