@namespace sv_7c3625fc74cc414b97ba7a94df488db7.Components.Pages.Apply

<div class="work-entry-form">
    <div class="entry-header">
        <h5>Position @(Index + 1)</h5>
        @if (CanRemove)
        {
            <button type="button" class="btn btn-sm btn-outline-danger" @onclick="OnRemove">Remove</button>
        }
    </div>

    <div class="row mb-2">
        <div class="col-md-6">
            <label class="form-label">Company Name *</label>
            <input type="text" class="form-control" value="@Entry.Company"
                   @onchange="OnCompanyChanged" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Job Title *</label>
            <input type="text" class="form-control" value="@Entry.Title"
                   @onchange="OnTitleChanged" />
        </div>
    </div>

    <div class="row mb-2">
        <div class="col-md-4">
            <label class="form-label">Start Date *</label>
            <input type="date" class="form-control" value="@StartDateString"
                   @onchange="OnStartDateChanged" />
        </div>
        <div class="col-md-4">
            <label class="form-label">End Date</label>
            <input type="date" class="form-control" value="@EndDateString"
                   disabled="@IsCurrent"
                   @onchange="OnEndDateChanged" />
        </div>
        <div class="col-md-4 d-flex align-items-end mb-1">
            <div class="form-check">
                <input type="checkbox" class="form-check-input" id="@CheckboxId" checked="@IsCurrent"
                       @onchange="OnCurrentChanged" />
                <label class="form-check-label" for="@CheckboxId">Currently working here</label>
            </div>
        </div>
    </div>

    <div class="mb-2">
        <label class="form-label">Description</label>
        <textarea class="form-control" rows="3" value="@Entry.Description"
                  @onchange="OnDescriptionChanged"></textarea>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntry Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback<WorkEntry> OnEntryChanged { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private bool IsCurrent => Entry.EndDate == null;
    private string StartDateString => Entry.StartDate.ToString("yyyy-MM-dd");
    private string EndDateString => Entry.EndDate?.ToString("yyyy-MM-dd") ?? string.Empty;
    private string CheckboxId => $"current-{Index}";

    private Task OnCompanyChanged(ChangeEventArgs e) =>
        OnEntryChanged.InvokeAsync(Entry with { Company = GetString(e) });

    private Task OnTitleChanged(ChangeEventArgs e) =>
        OnEntryChanged.InvokeAsync(Entry with { Title = GetString(e) });

    private Task OnStartDateChanged(ChangeEventArgs e)
    {
        var val = GetString(e);
        var date = string.IsNullOrEmpty(val) ? DateTime.Today : DateTime.Parse(val);
        return OnEntryChanged.InvokeAsync(Entry with { StartDate = date });
    }

    private Task OnEndDateChanged(ChangeEventArgs e)
    {
        var val = GetString(e);
        DateTime? date = string.IsNullOrEmpty(val) ? null : DateTime.Parse(val);
        return OnEntryChanged.InvokeAsync(Entry with { EndDate = date });
    }

    private Task OnCurrentChanged(ChangeEventArgs e)
    {
        var isCurrent = (bool)(e.Value ?? false);
        var updated = isCurrent
            ? Entry with { EndDate = null }
            : Entry with { EndDate = DateTime.Today };
        return OnEntryChanged.InvokeAsync(updated);
    }

    private Task OnDescriptionChanged(ChangeEventArgs e) =>
        OnEntryChanged.InvokeAsync(Entry with { Description = GetString(e) });

    private static string GetString(ChangeEventArgs e) =>
        e.Value?.ToString() ?? string.Empty;
}

