@namespace sv_7c3625fc74cc414b97ba7a94df488db7.Components.Pages.Apply

<div class="step-content">
    <h4>Personal Information</h4>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="alert alert-danger">@ErrorMessage</div>
    }

    <div class="mb-3">
        <label class="form-label">Full Name *</label>
        <input type="text" class="form-control" value="@FullName"
               @onchange="e => FullName = GetString(e)" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email *</label>
        <input type="email" class="form-control" value="@Email"
               @onchange="e => Email = GetString(e)" />
        @if (IsValidatingEmail)
        {
            <small class="text-muted">Validating email...</small>
        }
    </div>

    <div class="mb-3">
        <label class="form-label">Phone *</label>
        <input type="tel" class="form-control" value="@Phone"
               @onchange="e => Phone = GetString(e)" />
    </div>

    <div class="mb-3">
        <label class="form-label">Address *</label>
        <textarea class="form-control" rows="2" value="@Address"
                  @onchange="e => Address = GetString(e)"></textarea>
    </div>

    <div class="d-flex justify-content-end">
        <button type="button" class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidatingEmail">Next</button>
    </div>
</div>

@code {
    [Parameter] public PersonalInfo? Info { get; set; }
    [Parameter] public EventCallback<PersonalInfo> OnNext { get; set; }
    [Parameter] public IApplicationService ApplicationService { get; set; } = default!;

    private string FullName { get; set; } = string.Empty;
    private string Email { get; set; } = string.Empty;
    private string Phone { get; set; } = string.Empty;
    private string Address { get; set; } = string.Empty;
    private string? ErrorMessage { get; set; }
    private bool IsValidatingEmail { get; set; }

    protected override void OnParametersSet()
    {
        if (Info is not null)
        {
            FullName = Info.FullName;
            Email = Info.Email;
            Phone = Info.Phone;
            Address = Info.Address;
        }
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(FullName) || string.IsNullOrWhiteSpace(Email)
            || string.IsNullOrWhiteSpace(Phone) || string.IsNullOrWhiteSpace(Address))
        {
            ErrorMessage = "All fields are required.";
            return;
        }

        IsValidatingEmail = true;
        StateHasChanged();

        var isValid = await ApplicationService.ValidateEmailAsync(Email);
        IsValidatingEmail = false;

        if (!isValid)
        {
            ErrorMessage = "Please enter a valid email address.";
            return;
        }

        await OnNext.InvokeAsync(new PersonalInfo(FullName.Trim(), Email.Trim(), Phone.Trim(), Address.Trim()));
    }

    private static string GetString(ChangeEventArgs e) =>
        e.Value?.ToString() ?? string.Empty;
}

